1	type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	type Step = { op: "quote"; items: Item[] };
8	type Customer = { yearsWithMHPCO: number };
9	type Scenario = { customer: Customer; steps: Step[] };
10	type QuoteResult = { premium: number };
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_RATE = 0.1;
14	const CURSE_RATE = 0.5;
15	const COMPONENT_BASE_PREMIUM = 25;
16	const BLOCK_SIZE = 3;
17	const BLOCK_BASE_PREMIUM = 60;
18	
19	const BASE_PREMIUMS: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	};
25	
26	const isComponent = (item: Item): boolean => BASE_PREMIUMS[item.type] === undefined;
27	
28	const componentGroupBase = (count: number): number =>
29	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * COMPONENT_BASE_PREMIUM;
30	
31	const countByType = (items: Item[]): Map<string, number> =>
32	  items.reduce(
33	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
34	    new Map<string, number>(),
35	  );
36	
37	// Returns base premium attributed to a single main item (not components).
38	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
39	
40	// Components are priced per group with block discount.
41	const componentsBaseTotal = (components: Item[]): number =>
42	  [...countByType(components).values()].reduce(
43	    (sum, count) => sum + componentGroupBase(count),
44	    0,
45	  );
46	
47	// Base premium of the whole policy (raw, no item modifiers).
48	const policyBase = (items: Item[]): number => {
49	  const mainBase = items.filter((i) => !isComponent(i)).reduce((sum, i) => sum + itemBasePremium(i), 0);
50	  const compBase = componentsBaseTotal(items.filter(isComponent));
51	  return mainBase + compBase;
52	};
53	
54	// Surcharges that apply to a single item's base premium (cursed, high enchantment).
55	const itemSurcharge = (item: Item): number => {
56	  const base = isComponent(item) ? 0 : itemBasePremium(item);
57	  let surcharge = 0;
58	  if (item.cursed) surcharge += base * CURSE_RATE;
59	  return surcharge;
60	};
61	
62	const itemSurchargesTotal = (items: Item[]): number =>
63	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
64	
65	const quoteStep = (step: Step): QuoteResult => {
66	  const base = policyBase(step.items);
67	  const itemSurcharges = itemSurchargesTotal(step.items);
68	  const firstInsurance = base * FIRST_INSURANCE_RATE;
69	  const premium = Math.ceil(base + itemSurcharges + firstInsurance) + PROCESSING_FEE;
70	  return { premium };
71	};
72	
73	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
74	  const results = scenario.steps.map(quoteStep);
75	  return { results };
76	};
